def resolve_target(conn_type: str, target: dict[str, Any] | None) -> ResolvedTarget:
    """Resolve ``target`` for a ``conn_type`` connection, or raise (422).

    Raises `SuiteTargetInvalidError` if the suite is targetless, the target is
    missing the field its datasource requires (`path` for flat files, `table`
    for SQL, `catalog` for Unity Catalog), or the connection type has no run path
    (orchestration providers — they are never suite datasources).
    """
    if not target:
        raise SuiteTargetInvalidError(
            "suite has no target configured", detail={"connection_type": conn_type}
        )

    if conn_type in _FLATFILE_TYPES:
        # A batch target (regex `pattern`) is resolved to a concrete path at run
        # time; a literal target carries the `path` directly. The two are mutually
        # exclusive — both set is an ambiguous target, not a silent batch win.
        if "pattern" in target and target.get("path"):
            raise SuiteTargetInvalidError(
                "flat-file target is ambiguous: set either 'path' (literal) or "
                "'pattern' (batch), not both",
                detail={"connection_type": conn_type},
            )
        if "pattern" in target:
            return ResolvedTarget(
                table="", schema=None, catalog=None, batch=_batch_spec(target, conn_type)
            )
        path = _require(target, "path", conn_type)
        return ResolvedTarget(table=path, schema=None, catalog=None)

    """Celery-beat entry point — the 10-min orchestration polling fallback."""
    return _run_orchestration_poll(_POLL_LOOKBACK)


@celery_app.task(name="recover_orchestration_gaps")  # type: ignore[untyped-decorator]  # celery task decorator is unannotated
def recover_orchestration_gaps() -> dict[str, int]:
    """Celery-beat entry point — gap recovery (B2), startup + every 30 min.

    The same poll pipeline over the wider ``_GAP_RECOVERY_LOOKBACK`` window, to
    re-ingest runs missed while the system was down. Idempotent with the regular
    poll (upsert + `skip_updated_since`).
    """
    return _run_orchestration_poll(_GAP_RECOVERY_LOOKBACK)

